// src/pages/TestsResults.jsx
import tetotestMeta from '../tests/tetotest/meta';
import tetotestResults from '../tests/tetotest/resultDescriptions';
import tetotestImages from '../tests/tetotest/resultImages';

import sociopathMeta from '../tests/sociopathtest/meta';
import sociopathResults from '../tests/sociopathtest/resultDescriptions';
import sociopathImages from '../tests/sociopathtest/resultImages';

export default function TestsResults() {
  // 테스트별 데이터 구조
  const testResultSets = [
    {
      meta: tetotestMeta,
      results: tetotestResults, // 객체
      images: tetotestImages,
      isObject: true,
      description:
        "호르몬 유형 테스트는 다양한 남녀의 성향, 라이프스타일, 연애스타일까지 세밀하게 분류합니다. 아래 결과에서 당신의 유형과 특성을 확인해보세요!",
    },
    {
      meta: sociopathMeta,
      results: sociopathResults, // 배열
      images: sociopathImages,
      isObject: false,
      description:
        "직장 소시오패스 테스트는 실제 직장인 유형을 분석하여, 순수 천사부터 소시오패스 레전드까지 다양한 직장 내 민낯을 보여줍니다.",
    },
  ];

  return (
    <div className="max-w-2xl mx-auto p-6 pb-16">
      <h1 className="text-3xl font-bold mb-6 text-emerald-700">테스트별 결과 유형 모아보기</h1>
      <p className="mb-9 text-gray-600">
        각 테스트별로 등장하는 결과 유형과 해설, 이미지를 한눈에 볼 수 있습니다.
      </p>
      {testResultSets.map(({ meta, results, images, isObject, description }, i) => (
        <section key={meta.id} className="mb-14">
          <div className="flex items-center gap-4 mb-2">
            <img
              src={meta.image}
              alt={meta.title}
              className="w-12 h-12 rounded-lg object-cover border border-emerald-200"
            />
            <div>
              <h2 className="text-xl font-bold text-emerald-900">{meta.title}</h2>
              <p className="text-sm text-gray-500">{description}</p>
            </div>
          </div>
          <div className="grid gap-7 mt-3">
            {isObject
              ? Object.entries(results).map(([key, res], idx) => (
                  <div
                    key={key}
                    className="flex items-center bg-white rounded-xl shadow p-4 gap-4 border-l-4 border-emerald-300"
                  >
                    {images[idx] && (
                      <img
                        src={images[idx]}
                        alt={key}
                        className="w-20 h-20 object-cover rounded-xl border border-emerald-100 bg-gray-50"
                      />
                    )}
                    <div className="flex-1">
                      <div className="font-bold text-lg mb-1 text-emerald-800">{key}</div>
                      <div className="mb-1">
                        <span className="font-semibold text-green-600 text-sm mr-1">성격적 특성</span>
                        <span className="text-gray-700 text-sm">{res.성격적특성?.join(' / ')}</span>
                      </div>
                      <div className="mb-1">
                        <span className="font-semibold text-blue-600 text-sm mr-1">행동적 특성</span>
                        <span className="text-gray-700 text-sm">{res.행동적특성?.join(' / ')}</span>
                      </div>
                      <div>
                        <span className="font-semibold text-pink-600 text-sm mr-1">연애스타일</span>
                        <span className="text-gray-700 text-sm">{res.연애스타일?.join(' / ')}</span>
                      </div>
                    </div>
                  </div>
                ))
              : results.map((res, idx) => (
                  <div
                    key={res.id || res.name}
                    className="flex items-center bg-white rounded-xl shadow p-4 gap-4 border-l-4 border-red-200"
                  >
                    {images[idx] && (
                      <img
                        src={images[idx]}
                        alt={res.name}
                        className="w-20 h-20 object-cover rounded-xl border border-red-100 bg-gray-50"
                      />
                    )}
                    <div>
                      <div className="font-bold text-lg mb-1 text-red-500">{res.name}</div>
                      <div className="text-gray-700 text-sm">{res.description}</div>
                    </div>
                  </div>
                ))}
          </div>
        </section>
      ))}
    </div>
  );
}
